class Objectmanager {
  constructor(GameObject, liztobj, UTILS, config, _players, _server) {
    let mathFloor = Math.floor,
      mathABS = Math.abs,
      mathCOS = Math.cos,
      mathSIN = Math.sin,
      mathPOW = Math.pow,
      mathSQRT = Math.sqrt;

    this.ignoreAdd = false;
    this.hitObj = [];

    this.disableObj = function (obj) {
      obj.active = false;
    };

    let tmpObj;
    this.add = function (sid, x, y, dir, s, type, data, setSID, owner) {
      tmpObj = findObjectBySid(sid);
      if (!tmpObj) {
        tmpObj = gameObjects.find((tmp) => !tmp.active);
        if (!tmpObj) {
          tmpObj = new GameObject(sid);
          gameObjects.push(tmpObj);
        }
      }
      if (setSID) {
        tmpObj.sid = sid;
      }
      tmpObj.init(x, y, dir, s, type, data, owner);
    };

    this.disableBySid = function (sid) {
      let find = findObjectBySid(sid);
      if (find) {
        this.disableObj(find);
      }
    };

    this.removeAllItems = function (sid, _server) {
      gameObjects
        .filter((tmp) => tmp.active && tmp.owner && tmp.owner.sid == sid)
        .forEach((tmp) => this.disableObj(tmp));
    };

    this.checkItemLocation = function (
      x,
      y,
      s,
      sM,
      indx,
      ignoreWater,
      _placer,
      ignoreSid,
    ) {
      let cantPlace = liztobj.find(
        (tmp) =>
          tmp.active &&
          tmp.sid !== ignoreSid &&
          UTILS.getDistance(x, y, tmp.x, tmp.y) <
          s + (tmp.blocker ? tmp.blocker : tmp.getScale(sM, tmp.isItem)),
      );
      if (cantPlace) return false;
      if (
        !ignoreWater &&
        indx != 18 &&
        y >= config.mapScale / 2 - config.riverWidth / 2 &&
        y <= config.mapScale / 2 + config.riverWidth / 2
      )
        return false;
      return true;
    };
  }
}
class Projectile {
  constructor(_players, _ais, _objectManager, _items, _config, UTILS, _server) {
    this.init = function (indx, x, y, dir, spd, dmg, rng, scl, owner) {
      this.active = true;
      this.tickActive = true;
      this.indx = indx;
      this.x = x;
      this.y = y;
      this.x2 = x;
      this.y2 = y;
      this.dir = dir;
      this.skipMov = true;
      this.speed = spd;
      this.dmg = dmg;
      this.scale = scl;
      this.range = rng;
      this.r2 = rng;
      this.owner = owner;
    };

    this.update = function (delta) {
      if (this.active) {
        let tmpSpeed = this.speed * delta;
        if (!this.skipMov) {
          const nextX = this.x + tmpSpeed * Math.cos(this.dir);
          const nextY = this.y + tmpSpeed * Math.sin(this.dir);
          for (const obj of gameObjects) {
            if (!obj.active) continue;
            const objScale = obj.blocker
              ? obj.blocker
              : obj.getScale(0.6, obj.isItem);
            const dist = UTILS.getDistance(nextX, nextY, obj.x, obj.y);
            if (dist < objScale) {
              this.active = false;
              return;
            }
          }
          for (const obj of liztobj) {
            if (!obj.active) continue;
            const objScale = obj.blocker
              ? obj.blocker
              : obj.getScale(0.6, obj.isItem);
            const dist = UTILS.getDistance(nextX, nextY, obj.x, obj.y);
            if (dist < objScale) {
              this.active = false;
              return;
            }
          }
          this.x = nextX;
          this.y = nextY;
          this.range -= tmpSpeed;
          if (this.range <= 0) {
            this.x += this.range * Math.cos(this.dir);
            this.y += this.range * Math.sin(this.dir);
            tmpSpeed = 1;
            this.range = 0;
            this.active = false;
          }
        } else {
          this.skipMov = false;
        }
      }
    };
    this.tickUpdate = function (delta) {
      if (this.tickActive) {
        let tmpSpeed = this.speed * delta;
        if (!this.skipMov) {
          this.x2 += tmpSpeed * Math.cos(this.dir);
          this.y2 += tmpSpeed * Math.sin(this.dir);
          this.r2 -= tmpSpeed;
          if (this.r2 <= 0) {
            this.x2 += this.r2 * Math.cos(this.dir);
            this.y2 += this.r2 * Math.sin(this.dir);
            tmpSpeed = 1;
            this.r2 = 0;
            this.tickActive = false;
          }
        } else {
          this.skipMov = false;
        }
      }
    };
  }
}
