function autoPush() {
  let nearTrap = gameObjects
    .filter(
      (tmp) =>
        tmp.trap &&
        tmp.active &&
        tmp.isTeamObject(player) &&
        UTILS.getDist(tmp, near, 0, 2) <= near.scale + tmp.getScale() + 5,
    )
    .sort(function (a, b) {
      return UTILS.getDist(a, near, 0, 2) - UTILS.getDist(b, near, 0, 2);
    })[0];

  if (nearTrap) {
    let spike = gameObjects
      .filter(
        (tmp) =>
          tmp.dmg &&
          tmp.active &&
          tmp.isTeamObject(player) &&
          UTILS.getDist(tmp, nearTrap, 0, 0) <=
          near.scale + nearTrap.scale + tmp.scale,
      )
      .sort(function (a, b) {
        return UTILS.getDist(a, near, 0, 2) - UTILS.getDist(b, near, 0, 2);
      })[0];

    if (spike) {
      let pushAngle = Math.atan2(near.y2 - spike.y, near.x2 - spike.x);

      let pos = {
        x: spike.x + 250 * Math.cos(UTILS.getDir(near, spike, 2, 0)),
        y: spike.y + 250 * Math.sin(UTILS.getDir(near, spike, 2, 0)),
        x2:
          spike.x +
          (UTILS.getDist(near, spike, 2, 0) + player.scale) *
          Math.cos(UTILS.getDir(near, spike, 2, 0)) +
          Math.cos(25),
        y2:
          spike.y +
          (UTILS.getDist(near, spike, 2, 0) + player.scale) *
          Math.sin(UTILS.getDir(near, spike, 2, 0)) +
          Math.sin(25),
      };

      let finds = gameObjects
        .filter((tmp) => tmp.active)
        .find((tmp) => {
          let tmpScale = tmp.getScale();
          if (
            !tmp.ignoreCollision &&
            UTILS.lineInRect(
              tmp.x - tmpScale,
              tmp.y - tmpScale,
              tmp.x + tmpScale,
              tmp.y + tmpScale,
              player.x2,
              player.y2,
              pos.x2,
              pos.y2,
            )
          ) {
            return true;
          }
        });

      if (finds) {
        if (my.autoPush) {
          my.autoPush = false;
          packet("9", undefined, 1);
        }
      } else {
        my.autoPush = true;
        instaC.setAutoPush();
        instaC.lastTarget = near?.name || "Unknown";
        my.pushData = {
          x: spike.x + Math.cos(pushAngle),
          y: spike.y + Math.sin(pushAngle),
          x2: player.x2 + 30,
          y2: player.y2 + 30,
        };

        let point = {
          x: near.x2 + Math.cos(pushAngle) * 30,
          y: near.y2 + Math.sin(pushAngle) * 60,
        };

        let dir = Math.atan2(point.y - player.y2, point.x - player.x2);

        packet("9", dir, 1);
        let scale = player.scale / 10;
        if (
          UTILS.lineInRect(
            player.x2 - scale,
            player.y2 - scale,
            player.x2 + scale,
            player.y2 + scale,
            near.x2,
            near.y2,
            pos.x,
            pos.y,
          )
        ) {
          packet("9", near.aim2, 1);
        } else {
          packet("9", UTILS.getDir(pos, player, 2, 2), 1);
        }
      }
    } else {
      if (my.autoPush) {
        my.autoPush = false;
        packet("9", undefined, 1);
      }
    }
  } else {
    if (my.autoPush) {
      my.autoPush = false;
      packet("9", undefined, 1);
    }
  }
}

