function fgdo(a, b) {
  return Math.sqrt(Math.pow(b.y - a.y, 2) + Math.pow(b.x - a.x, 2));
}
function setTickout(doo, timeout) {
  if (!ticks.manage[ticks.tick + timeout]) {
    ticks.manage[ticks.tick + timeout] = [doo];
  } else {
    ticks.manage[ticks.tick + timeout].push(doo);
  }
}

function caf(e, t) {
  try {
    return Math.atan2(
      (t.y2 || t.y) - (e.y2 || e.y),
      (t.x2 || t.x) - (e.x2 || e.x),
    );
  } catch (e) {
    return 0;
  }
}

